import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';

import { ROUTES } from '../utils/constants';
import ProtectedRoute from '../components/common/ProtectedRoute';
import DashboardLayout from '../layouts/DashboardLayout';

import LandingPage    from '../pages/LandingPage';
import LoginPage      from '../pages/LoginPage';
import RegisterPage   from '../pages/RegisterPage';
import DashboardPage  from '../pages/DashboardPage';
import ResumePage     from '../pages/ResumePage';
import CodingPage     from '../pages/CodingPage';
import InterviewPage  from '../pages/InterviewPage';
import CareerPage     from '../pages/CareerPage';
import SkillGapPage   from '../pages/SkillGapPage';
import NotFoundPage   from '../pages/NotFoundPage';

/**
 * Central route configuration.
 *
 * Public  : /  /login  /register
 * Protected (need JWT): everything under DashboardLayout
 * Fallback: * → 404
 */
function AppRoutes() {
  return (
    <Routes>
      {/* Public routes */}
      <Route path={ROUTES.HOME}     element={<LandingPage />} />
      <Route path={ROUTES.LOGIN}    element={<LoginPage />} />
      <Route path={ROUTES.REGISTER} element={<RegisterPage />} />

      {/* Protected routes — all share DashboardLayout */}
      <Route
        element={
          <ProtectedRoute>
            <DashboardLayout />
          </ProtectedRoute>
        }
      >
        <Route path={ROUTES.DASHBOARD} element={<DashboardPage />} />
        <Route path={ROUTES.RESUME}    element={<ResumePage />} />
        <Route path={ROUTES.CODING}    element={<CodingPage />} />
        <Route path={ROUTES.INTERVIEW} element={<InterviewPage />} />
        <Route path={ROUTES.CAREER}    element={<CareerPage />} />
        <Route path={ROUTES.SKILL_GAP} element={<SkillGapPage />} />
      </Route>

      {/* 404 fallback */}
      <Route path="*" element={<NotFoundPage />} />
    </Routes>
  );
}

export default AppRoutes;
